const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryData = item.binary?.data;
  if (!binaryData) {
    results.push({
      json: {
        error: true,
        message: 'No binary data found',
        originalFileName: item.json.name || 'unknown'
      }
    });
    continue;
  }

  const binaryBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const base64 = binaryBuffer.toString('base64');

  const mimeType = binaryData.mimeType || 'application/octet-stream';
  const fileName = item.json.name || binaryData.fileName || 'unknown';

  results.push({
    json: {
      base64Data: base64,
      mimeType: mimeType,
      originalFileName: fileName,
      fileId: item.json.id || '',
      error: false
    }
  });
}

return results;

