parameters.jsCode:
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const response = item.json;
    let content = '';

    if (response.candidates && response.candidates[0]) {
      content = response.candidates[0].content.parts[0].text;
    }

    let parsed;
    try {
      content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      parsed = JSON.parse(content);
    } catch (parseErr) {
      throw new Error('JSON parse failed: ' + parseErr.message);
    }

    const confidence = parsed.confidence || 0;
    const isValid = confidence >= 0.6 && parsed.document_type && parsed.document_type !== 'other';
    const prevData = $('Convert to Base64').first().json;

    results.push({
      json: {
        ...parsed,
        isValid: isValid,
        parseError: false,
        originalFileName: prevData.originalFileName || '',
        fileId: prevData.fileId || '',
        processedAt: new Date().toISOString()
      }
    });
  } catch (err) {
    const prevData = $('Convert to Base64').first().json;
    results.push({
      json: {
        isValid: false,
        parseError: true,
        errorMessage: err.message,
        originalFileName: prevData?.originalFileName || 'unknown',
        fileId: prevData?.fileId || '',
        processedAt: new Date().toISOString()
      }
    });
  }
}

return results;

const item = $input.first().json;

// Document type prefix mapping
const typeMap = {
  'invoice': 'INV',
  'estimate': 'EST',
  'contract': 'CON',
  'receipt': 'REC',
  'application': 'APP',
  'inquiry': 'INQ',
  'delivery_note': 'DLV',
  'purchase_order': 'ORD',
  'other': 'OTH'
};

// ★ Set your Google Drive folder IDs for each document type ★
const folderMap = {
  'invoice': 'YOUR_INVOICE_FOLDER_ID',
  'estimate': 'YOUR_ESTIMATE_FOLDER_ID',
  'contract': 'YOUR_CONTRACT_FOLDER_ID',
  'receipt': 'YOUR_RECEIPT_FOLDER_ID',
  'application': 'YOUR_APPLICATION_FOLDER_ID',
  'inquiry': 'YOUR_INQUIRY_FOLDER_ID',
  'delivery_note': 'YOUR_DELIVERY_NOTE_FOLDER_ID',
  'purchase_order': 'YOUR_PURCHASE_ORDER_FOLDER_ID',
  'other': 'YOUR_OTHER_FOLDER_ID'
};

const prefix = typeMap[item.document_type] || 'OTH';
const date = item.document_date || new Date().toISOString().slice(0, 10);
const company = (item.company_name || 'unknown').replace(/[\\\/\/:*?"<>|]/g, '_').slice(0, 20);
const ext = item.originalFileName ? item.originalFileName.split('.').pop() : 'pdf';
const newFileName = prefix + '_' + date.replace(/-/g, '') + '_' + company + '.' + ext;
const targetFolderId = folderMap[item.document_type] || folderMap['other'];

return [{
  json: {
    ...item,
    newFileName: newFileName,
    targetFolderId: targetFolderId,
    typePrefix: prefix
  }
}];

